import{_ as i}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as n,c as t,f as l,q as a,D as p,N as d,g as r}from"./chunks/runtime-core.esm-bundler.DuRo-bNR.js";const C=JSON.parse('{"title":"个人档案 Archive 在 ECS 上的生产部署实战：从源码拉取到产物直传的落地总结","description":"","frontmatter":{},"headers":[],"relativePath":"column/Aliyun/实战部署/Nuxt项目自动部署到ECS.md","filePath":"column/Aliyun/实战部署/Nuxt项目自动部署到ECS.md","lastUpdated":1780309918000}'),o={name:"column/Aliyun/实战部署/Nuxt项目自动部署到ECS.md"};function c(h,s,u,b,k,g){const e=n("ArticleMetadata");return l(),t("div",null,[s[0]||(s[0]=a("h1",{id:"个人档案-archive-在-ecs-上的生产部署实战-从源码拉取到产物直传的落地总结",tabindex:"-1"},[r("个人档案 Archive 在 ECS 上的生产部署实战：从源码拉取到产物直传的落地总结 "),a("a",{class:"header-anchor",href:"#个人档案-archive-在-ecs-上的生产部署实战-从源码拉取到产物直传的落地总结","aria-label":'Permalink to "个人档案 Archive 在 ECS 上的生产部署实战：从源码拉取到产物直传的落地总结"'},"​")],-1)),p(e),s[1]||(s[1]=d(`<p>把一个 Nuxt 项目真正部署到 ECS，问题往往不出在“怎么运行起来”，而是出在“怎么稳定地跑下去”。如果项目里同时用了 SQLite、本地上传目录、PM2、Nginx 和 <code>better-sqlite3</code> 这种原生模块，部署方案稍微想当然一点，上线后就很容易踩坑。</p><p>这篇文章结合一个真实项目，把这次部署过程完整复盘一遍：为什么一开始的方案要调整，为什么最终选择了“GitHub Actions 构建产物并直接上传 ECS”，以及几个关键问题是怎么被定位和修掉的。</p><h2 id="一、项目背景" tabindex="-1">一、项目背景 <a class="header-anchor" href="#一、项目背景" aria-label="Permalink to &quot;一、项目背景&quot;">​</a></h2><p>项目名称叫“个人档案 Archive”，它是一个本地优先的私人资料管理系统，主要用于集中管理：</p><ul><li>账号密码</li><li>文档资料</li><li>简历文件</li><li>图片文件</li><li>证件文件</li><li>学习资料</li></ul><p>当前技术栈如下：</p><table tabindex="0"><thead><tr><th>类型</th><th>技术</th></tr></thead><tbody><tr><td>前端框架</td><td>Nuxt 4、Vue 3</td></tr><tr><td>开发语言</td><td>TypeScript</td></tr><tr><td>UI 和样式</td><td>Element Plus、SCSS</td></tr><tr><td>服务端</td><td>Nuxt Server API</td></tr><tr><td>数据库</td><td>SQLite</td></tr><tr><td>数据访问</td><td>better-sqlite3</td></tr><tr><td>进程管理</td><td>PM2</td></tr><tr><td>反向代理</td><td>Nginx</td></tr><tr><td>自动部署</td><td>GitHub Actions</td></tr></tbody></table><p>这个项目有两个部署上的特点：</p><ol><li>数据库不是 MySQL、PostgreSQL，而是 SQLite。</li><li>上传文件不是对象存储，而是 ECS 本机目录。</li></ol><p>这意味着部署不能只考虑代码，还必须把数据目录和运行目录分离开。</p><h2 id="二、最初的部署思路为什么不合适" tabindex="-1">二、最初的部署思路为什么不合适 <a class="header-anchor" href="#二、最初的部署思路为什么不合适" aria-label="Permalink to &quot;二、最初的部署思路为什么不合适&quot;">​</a></h2><p>一开始最自然的思路，是让 ECS 在部署时自己拉源码：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub Actions -&gt; SSH 登录 ECS -&gt; git pull -&gt; npm ci -&gt; npm run build -&gt; pm2 restart</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个方案的优点很明显：</p><ul><li>简单直接</li><li>不用处理构建产物上传</li><li>ECS 上看到的是完整项目目录</li></ul><p>但它很快暴露出几个问题。</p><h3 id="_1-首次部署时目录里根本不是-git-仓库" tabindex="-1">1. 首次部署时目录里根本不是 Git 仓库 <a class="header-anchor" href="#_1-首次部署时目录里根本不是-git-仓库" aria-label="Permalink to &quot;1. 首次部署时目录里根本不是 Git 仓库&quot;">​</a></h3><p>如果 <code>/var/www/archive</code> 只是一个空目录，工作流里执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fetch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>就会直接报错：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fatal: not a git repository</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可以继续给工作流补“自动 <code>git init</code>、自动加 remote、自动拉分支”的逻辑，但这说明 ECS 已经开始承担“代码仓库管理”的职责了。</p><h3 id="_2-ecs-每次都要承担完整构建职责" tabindex="-1">2. ECS 每次都要承担完整构建职责 <a class="header-anchor" href="#_2-ecs-每次都要承担完整构建职责" aria-label="Permalink to &quot;2. ECS 每次都要承担完整构建职责&quot;">​</a></h3><p>源码部署意味着 ECS 每次发布都需要：</p><ul><li>有完整 Node 环境</li><li>能装依赖</li><li>能跑构建</li><li>能处理所有构建期依赖</li></ul><p>这会让 ECS 既是运行机，又是构建机。个人项目能跑，但结构不够清晰。</p><h3 id="_3-源码目录和运行目录混在一起" tabindex="-1">3. 源码目录和运行目录混在一起 <a class="header-anchor" href="#_3-源码目录和运行目录混在一起" aria-label="Permalink to &quot;3. 源码目录和运行目录混在一起&quot;">​</a></h3><p>如果同时把源码、<code>.env.production</code>、<code>.output</code>、SQLite 路径、上传目录都堆在一起，后面排查问题会越来越乱。</p><h2 id="三、为什么最终改成-产物直传" tabindex="-1">三、为什么最终改成“产物直传” <a class="header-anchor" href="#三、为什么最终改成-产物直传" aria-label="Permalink to &quot;三、为什么最终改成“产物直传”&quot;">​</a></h2><p>结合项目规模和维护成本，最终采用的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub Actions 构建产物 -&gt; 上传到 ECS -&gt; ECS 只负责解压与重启</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>具体来说，就是 GitHub Actions 负责：</p><ol><li>checkout 代码</li><li>安装依赖</li><li>构建 Nuxt <code>.output</code></li><li>生成 PM2 的 <code>ecosystem.config.cjs</code></li><li>打包成压缩文件</li><li>上传到 ECS</li></ol><p>ECS 只负责：</p><ol><li>解压产物到 <code>/var/www/archive</code></li><li>保留 <code>.env.production</code></li><li>保留数据库目录和上传目录</li><li>通过 PM2 重启服务</li></ol><p>对于这个项目来说，这个方案更合适，原因很简单：</p><ul><li>ECS 不需要再维护 Git 仓库状态</li><li>发布目录职责更明确</li><li>数据目录和运行目录天然分离</li><li>部署逻辑更接近真正的生产发布</li></ul><h2 id="四、最终的目录结构" tabindex="-1">四、最终的目录结构 <a class="header-anchor" href="#四、最终的目录结构" aria-label="Permalink to &quot;四、最终的目录结构&quot;">​</a></h2><p>最终落地的目录结构如下：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/www/archive</span></span>
<span class="line"><span>├── .env.production</span></span>
<span class="line"><span>├── .output</span></span>
<span class="line"><span>└── ecosystem.config.cjs</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/var/www/archive-data</span></span>
<span class="line"><span>├── data</span></span>
<span class="line"><span>│   └── archive.db</span></span>
<span class="line"><span>└── uploads</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>其中：</p><ul><li><code>/var/www/archive</code>：只放运行产物和生产环境变量</li><li><code>/var/www/archive-data/data</code>：SQLite 数据库</li><li><code>/var/www/archive-data/uploads</code>：上传文件</li></ul><p>这种结构的核心原则是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>代码和运行产物可以覆盖，数据库和上传文件必须持久化。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="五、最终的访问链路" tabindex="-1">五、最终的访问链路 <a class="header-anchor" href="#五、最终的访问链路" aria-label="Permalink to &quot;五、最终的访问链路&quot;">​</a></h2><p>这次部署过程中，服务监听和对外端口也做了调整。</p><p>最终链路是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公网 8081 -&gt; Nginx -&gt; 127.0.0.1:3000 -&gt; Nuxt/PM2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其中：</p><ul><li>Nuxt/PM2 只监听 ECS 本机 <code>127.0.0.1:3000</code></li><li>Nginx 对外监听 <code>8081</code></li><li>浏览器访问入口统一是 Nginx</li></ul><p>这样做有两个好处：</p><ol><li>Node 服务不直接暴露到公网。</li><li>后续切 HTTPS、域名、限流、日志都会更顺手。</li></ol><p>Nginx 配置核心如下：</p><div class="language-nginx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8081</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">_;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:3000;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_http_version </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-For $proxy_add_x_forwarded_for;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-Proto $scheme;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="六、github-actions-最终负责什么" tabindex="-1">六、GitHub Actions 最终负责什么 <a class="header-anchor" href="#六、github-actions-最终负责什么" aria-label="Permalink to &quot;六、GitHub Actions 最终负责什么&quot;">​</a></h2><p>这次部署落地后，GitHub Actions 的职责是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>checkout</span></span>
<span class="line"><span>-&gt; npm ci</span></span>
<span class="line"><span>-&gt; npm run build:prod</span></span>
<span class="line"><span>-&gt; 打包 .output + ecosystem.config.cjs</span></span>
<span class="line"><span>-&gt; 上传 deploy-artifact.tar.gz</span></span>
<span class="line"><span>-&gt; SSH 登录 ECS</span></span>
<span class="line"><span>-&gt; 解压到 /var/www/archive</span></span>
<span class="line"><span>-&gt; pm2 restart archive --update-env</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>注意这里构建命令用的是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:prod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也就是 GitHub Actions 会先在仓库中准备一个临时 <code>.env.production</code>，再按生产命令构建；它不依赖 ECS 机器上的真实 <code>.env.production</code>。 真正的生产环境变量，只保留在 ECS 的：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/www/archive/.env.production</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="七、部署过程中踩到的几个关键坑" tabindex="-1">七、部署过程中踩到的几个关键坑 <a class="header-anchor" href="#七、部署过程中踩到的几个关键坑" aria-label="Permalink to &quot;七、部署过程中踩到的几个关键坑&quot;">​</a></h2><p>这次部署真正有价值的部分，不是“把项目部署上去”，而是把这些坑逐个踩明白。</p><h3 id="_1-pm2-重载导致端口冲突" tabindex="-1">1. PM2 重载导致端口冲突 <a class="header-anchor" href="#_1-pm2-重载导致端口冲突" aria-label="Permalink to &quot;1. PM2 重载导致端口冲突&quot;">​</a></h3><p>一开始部署脚本里用了：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pm2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> startOrReload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ecosystem.config.cjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> archive</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --update-env</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但这个项目是单实例 <code>fork</code> 模式，而且固定监听 <code>127.0.0.1:3000</code>。在某些时机下，旧进程没完全退出，新进程就开始抢端口，结果直接报：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error: listen EADDRINUSE: address already in use 127.0.0.1:3000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最终改成：</p><ul><li>如果应用已存在，执行 <code>pm2 restart</code></li><li>如果应用不存在，执行 <code>pm2 start</code></li></ul><p>这样避免了 <code>reload</code> 带来的双进程抢端口问题。</p><h3 id="_2-better-sqlite3-原生模块和-node-版本不一致" tabindex="-1">2. better-sqlite3 原生模块和 Node 版本不一致 <a class="header-anchor" href="#_2-better-sqlite3-原生模块和-node-版本不一致" aria-label="Permalink to &quot;2. better-sqlite3 原生模块和 Node 版本不一致&quot;">​</a></h3><p>项目用了 <code>better-sqlite3</code>，它不是纯 JavaScript 包，而是原生模块。</p><p>这意味着一个非常关键的事实：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>构建产物所使用的 Node 大版本，必须和 ECS 实际运行的 Node 大版本一致。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>中间曾经出现过这样的错误：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Module did not self-register: better_sqlite3.node</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>根因是：</p><ul><li>GitHub Actions 用 Node 22 构建</li><li>ECS 实际运行是 Node 20</li><li><code>better-sqlite3</code> 的二进制 ABI 不兼容</li></ul><p>后来也尝试过在 ECS 上直接：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebuild</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> better-sqlite3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但 Nuxt <code>.output/server</code> 里的依赖并不是完整源码包结构，这种修法并不稳，甚至会报：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>binding.gyp not found</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最终的正确修复方式是：</p><ul><li>GitHub Actions 固定使用 Node 20</li><li>部署时额外校验 ECS 也是 Node 20.x</li></ul><p>也就是说，不是在 ECS 上“补救原生模块”，而是在构建时就保证 ABI 一致。</p><h3 id="_3-http-部署下的-csrf-cookie-问题" tabindex="-1">3. HTTP 部署下的 CSRF Cookie 问题 <a class="header-anchor" href="#_3-http-部署下的-csrf-cookie-问题" aria-label="Permalink to &quot;3. HTTP 部署下的 CSRF Cookie 问题&quot;">​</a></h3><p>项目登录态采用的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HttpOnly 签名 Cookie + CSRF Token</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>一开始服务端对生产环境直接用了：</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">secure</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isProduction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这在 HTTPS 下没有问题，但当前部署入口是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://公网IP:8081</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也就是纯 HTTP。</p><p>浏览器对于 <code>Secure</code> Cookie 的规则很明确：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP 请求不会保存或发送 Secure Cookie。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>于是现象就变成了：</p><ul><li><p>页面能打开</p></li><li><p>登录请求返回</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;LOGIN_FAILED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CSRF 令牌无效&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><p>原因不是 CSRF 算法错了，而是：</p><ul><li>浏览器根本没有保存 <code>archive_csrf</code></li><li>服务端校验时拿不到 Cookie</li></ul><p>最终修复逻辑改成：</p><ul><li>开发环境：<code>secure = false</code></li><li>生产环境： <ul><li>如果当前请求是 HTTPS，或者 <code>NUXT_PUBLIC_ORIGIN</code> 是 <code>https://...</code></li><li>才把 Cookie 标记为 <code>Secure</code></li></ul></li></ul><p>这样 HTTP <code>8081</code> 部署也能正常登录，后续切 HTTPS 时又能自动回到更安全的模式。</p><h3 id="_4-502-bad-gateway-并不一定是-nginx-配错了" tabindex="-1">4. 502 Bad Gateway 并不一定是 Nginx 配错了 <a class="header-anchor" href="#_4-502-bad-gateway-并不一定是-nginx-配错了" aria-label="Permalink to &quot;4. 502 Bad Gateway 并不一定是 Nginx 配错了&quot;">​</a></h3><p>部署时出现过一次 <code>502 Bad Gateway</code>，直觉很容易怀疑 Nginx。</p><p>但这次实际定位下来，真正的问题是：</p><ul><li>后端进程没起来</li><li>或者 PM2 在重载时因为端口冲突失败</li><li>或者 <code>better-sqlite3</code> 在进程启动后第一次访问数据库时崩掉</li></ul><p>所以这次部署也验证了一个很实用的排查顺序：</p><ol><li>先看 PM2 状态</li><li>再看 Node 是否监听 <code>127.0.0.1:3000</code></li><li>再看 Nginx 反向代理配置</li></ol><p>而不是一上来就盯着 Nginx。</p><h2 id="八、最终稳定下来的配置原则" tabindex="-1">八、最终稳定下来的配置原则 <a class="header-anchor" href="#八、最终稳定下来的配置原则" aria-label="Permalink to &quot;八、最终稳定下来的配置原则&quot;">​</a></h2><p>这次部署跑通后，最终沉淀下来的几个原则是：</p><h3 id="_1-运行目录和数据目录必须分离" tabindex="-1">1. 运行目录和数据目录必须分离 <a class="header-anchor" href="#_1-运行目录和数据目录必须分离" aria-label="Permalink to &quot;1. 运行目录和数据目录必须分离&quot;">​</a></h3><p>不要把 SQLite、上传文件和发布产物混在一起。</p><h3 id="_2-node-大版本必须统一" tabindex="-1">2. Node 大版本必须统一 <a class="header-anchor" href="#_2-node-大版本必须统一" aria-label="Permalink to &quot;2. Node 大版本必须统一&quot;">​</a></h3><p>GitHub Actions 和 ECS 的 Node 版本必须保持一致，尤其项目里用了 <code>better-sqlite3</code> 这种原生模块时，这一点不是建议，而是硬要求。</p><h3 id="_3-反向代理和服务监听职责分清" tabindex="-1">3. 反向代理和服务监听职责分清 <a class="header-anchor" href="#_3-反向代理和服务监听职责分清" aria-label="Permalink to &quot;3. 反向代理和服务监听职责分清&quot;">​</a></h3><p>Nginx 负责对外，Nuxt 只负责本机监听。</p><h3 id="_4-cookie-安全策略要和实际协议一致" tabindex="-1">4. Cookie 安全策略要和实际协议一致 <a class="header-anchor" href="#_4-cookie-安全策略要和实际协议一致" aria-label="Permalink to &quot;4. Cookie 安全策略要和实际协议一致&quot;">​</a></h3><p>HTTP 部署下不能一刀切地把所有 Cookie 都标成 <code>Secure</code>。</p><h3 id="_5-个人项目可以简化-但边界不能糊" tabindex="-1">5. 个人项目可以简化，但边界不能糊 <a class="header-anchor" href="#_5-个人项目可以简化-但边界不能糊" aria-label="Permalink to &quot;5. 个人项目可以简化，但边界不能糊&quot;">​</a></h3><p>这次最终没有上 <code>releases/current</code> 这种版本目录结构，而是直接覆盖 <code>/var/www/archive</code>。对个人项目来说，这样更简单，也更符合维护成本。</p><p>但即使简化部署结构，也不能牺牲这些底层边界：</p><ul><li>数据目录独立</li><li>Node 版本一致</li><li>反向代理明确</li><li>进程管理明确</li><li>环境变量不入库</li></ul><h2 id="九、最终方案总结" tabindex="-1">九、最终方案总结 <a class="header-anchor" href="#九、最终方案总结" aria-label="Permalink to &quot;九、最终方案总结&quot;">​</a></h2><p>这次部署最终稳定下来的方案可以总结为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub Actions 使用 Node 20 构建 Nuxt 产物</span></span>
<span class="line"><span>-&gt; 将 .output 和 PM2 配置打包上传到 ECS</span></span>
<span class="line"><span>-&gt; ECS 解压到 /var/www/archive</span></span>
<span class="line"><span>-&gt; PM2 监听 127.0.0.1:3000</span></span>
<span class="line"><span>-&gt; Nginx 对外监听 8081</span></span>
<span class="line"><span>-&gt; SQLite 和 uploads 持久化在 /var/www/archive-data</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>对应的部署心智模型也可以总结成一句话：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>代码产物可以覆盖，数据不能覆盖；访问入口交给 Nginx，应用只负责本机服务；原生模块是否稳定，首先看 Node 版本是否一致。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="十、结语" tabindex="-1">十、结语 <a class="header-anchor" href="#十、结语" aria-label="Permalink to &quot;十、结语&quot;">​</a></h2><p>很多部署问题表面上看是“某一条命令报错了”，但真正要解决的是部署模型本身是否合理。</p><p>这次从源码拉取部署，调整到产物直传部署；从端口冲突，修到 PM2 启动策略；从 <code>better-sqlite3</code> 报错，定位到 Node ABI 一致性；再到 HTTP 下的 CSRF Cookie 失效，本质上都指向同一个结论：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>部署不是把项目跑起来，而是把运行边界划清楚。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果项目只是个人使用，方案当然可以简化；但只要涉及 ECS、反向代理、原生依赖和真实登录链路，结构必须是清楚的，不能靠“先跑起来再说”长期维持。</p><p>这也是这次部署过程里最值得保留下来的经验。</p>`,135))])}const E=i(o,[["render",c]]);export{C as __pageData,E as default};
